import json
import sys
import random

class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

class Solution:
    def __init__(self, head):
        self.head = head

    def getRandom(self):
        result = self.head.val
        current = self.head.next
        i = 2

        while current:
            # Replace with probability 1/i
            if random.randint(0, i - 1) == 0:
                result = current.val
            current = current.next
            i += 1

        return result

def build_linked_list(arr):
    if not arr:
        return None
    head = ListNode(arr[0])
    current = head
    for val in arr[1:]:
        current.next = ListNode(val)
        current = current.next
    return head

def solution(head):
    sol = Solution(head)
    return sol.getRandom()

# Read input
lines = sys.stdin.read().strip().split('\n')
head_arr = json.loads(lines[0])
head = build_linked_list(head_arr)
result = solution(head)
