#include <iostream>
#include <vector>
#include <string>
#include <sstream>
#include <cstdlib>
#include <ctime>
#include <algorithm>
using namespace std;

struct ListNode {
    int val;
    ListNode* next;
    ListNode(int x) : val(x), next(nullptr) {}
};

class Solution {
public:
    ListNode* head;

    Solution(ListNode* head) : head(head) {
        srand(time(nullptr));
    }

    int getRandom() {
        int result = head->val;
        ListNode* current = head->next;
        int i = 2;

        while (current) {
            // Replace with probability 1/i
            if (rand() % i == 0) {
                result = current->val;
            }
            current = current->next;
            i++;
        }

        return result;
    }
};

ListNode* buildLinkedList(vector<int>& arr) {
    if (arr.empty()) return nullptr;
    ListNode* head = new ListNode(arr[0]);
    ListNode* current = head;
    for (int i = 1; i < arr.size(); i++) {
        current->next = new ListNode(arr[i]);
        current = current->next;
    }
    return head;
}

int solution(ListNode* head) {
    Solution sol(head);
    return sol.getRandom();
}

int main() {
    string line;
    getline(cin, line);
    vector<int> arr;

    // Remove brackets and parse
    line.erase(remove(line.begin(), line.end(), '['), line.end());
    line.erase(remove(line.begin(), line.end(), ']'), line.end());

    stringstream ss(line);
    string token;
    while (getline(ss, token, ',')) {
        arr.push_back(stoi(token));
    }

    ListNode* head = buildLinkedList(arr);
    cout << solution(head) << endl;
    return 0;
}

