#include <string>
#include <sstream>
#include <cstdlib>
#include <ctime>
#include <algorithm>
using namespace std;

struct ListNode {
    int val;
    ListNode* next;
    ListNode(int x) : val(x), next(nullptr) {}
};

class Solution {
public:
    ListNode* head;

    Solution(ListNode* head) : head(head) {
        srand(time(nullptr));
    }

    int getRandom() {
        // Count total nodes
        int count = 0;
        ListNode* current = head;
        while (current) {
            count++;
            current = current->next;
        }

        // Generate random index
        int randomIndex = rand() % count;

        // Traverse to random position
        current = head;
        for (int i = 0; i < randomIndex; i++) {
            current = current->next;
        }

        return current->val;
    }
};

ListNode* buildLinkedList(vector<int>& arr) {
    if (arr.empty()) return nullptr;
    ListNode* head = new ListNode(arr[0]);
    ListNode* current = head;
    for (int i = 1; i < arr.size(); i++) {
        current->next = new ListNode(arr[i]);
        current = current->next;
    }
    return head;
}

int solution(ListNode* head) {
    Solution sol(head);
    return sol.getRandom();
}

int main() {
    string line;
    getline(cin, line);
    vector<int> arr;

    // Remove brackets and parse
    line.erase(remove(line.begin(), line.end(), '['), line.end());
