const lines = fs.readFileSync(0, 'utf8').trim().split('\n');

function solution(nums1, nums2) {
    const n = nums1.length;
    const half = Math.floor(n / 2);

    const set1 = new Set(nums1);
    const set2 = new Set(nums2);

    // Elements only in nums1
    const only1 = new Set([...set1].filter(x => !set2.has(x)));
    // Elements only in nums2
    const only2 = new Set([...set2].filter(x => !set1.has(x)));
    // Elements in both arrays
    const common = new Set([...set1].filter(x => set2.has(x)));

    // From nums1: take unique first, then common if needed
    const takeOnly1 = Math.min(only1.size, half);
    const remainingFrom1 = half - takeOnly1;
    const takeCommonFrom1 = Math.min(common.size, remainingFrom1);

    // From nums2: take unique first, then common if needed
    const takeOnly2 = Math.min(only2.size, half);
    const remainingFrom2 = half - takeOnly2;
    const takeCommonFrom2 = Math.min(common.size, remainingFrom2);

    // Total common elements we can include (avoid double counting)
    const totalCommonTaken = Math.min(common.size, takeCommonFrom1 + takeCommonFrom2);

    return takeOnly1 + takeOnly2 + totalCommonTaken;
}

