import java.util.*;
import java.io.*;

class Main {
    public static int solution(int[] nums1, int[] nums2) {
        int n = nums1.length;
        int half = n / 2;

        Set<Integer> set1 = new HashSet<>();
        Set<Integer> set2 = new HashSet<>();

        for (int num : nums1) set1.add(num);
        for (int num : nums2) set2.add(num);

        // Elements only in nums1
        Set<Integer> only1 = new HashSet<>(set1);
        only1.removeAll(set2);

        // Elements only in nums2
        Set<Integer> only2 = new HashSet<>(set2);
        only2.removeAll(set1);

        // Elements in both arrays
        Set<Integer> common = new HashSet<>(set1);
        common.retainAll(set2);

        // From nums1: take unique first, then common if needed
        int takeOnly1 = Math.min(only1.size(), half);
        int remainingFrom1 = half - takeOnly1;
        int takeCommonFrom1 = Math.min(common.size(), remainingFrom1);

        // From nums2: take unique first, then common if needed
        int takeOnly2 = Math.min(only2.size(), half);
        int remainingFrom2 = half - takeOnly2;
        int takeCommonFrom2 = Math.min(common.size(), remainingFrom2);

        // Total common elements we can include
        int totalCommonTaken = Math.min(common.size(), takeCommonFrom1 + takeCommonFrom2);

        return takeOnly1 + takeOnly2 + totalCommonTaken;
    }

    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        String line1 = sc.nextLine().trim();
        String line2 = sc.nextLine().trim();

        int[] nums1 = parseArray(line1);
        int[] nums2 = parseArray(line2);

        System.out.println(solution(nums1, nums2));
    }

    private static int[] parseArray(String s) {
        s = s.substring(1, s.length() - 1);
        if (s.isEmpty()) return new int[0];
        String[] parts = s.split(",");
        int[] arr = new int[parts.length];
        for (int i = 0; i < parts.length; i++) {
            arr[i] = Integer.parseInt(parts[i].trim());
        }
        return arr;
    }
}

