#include <iostream>
#include <vector>
#include <unordered_set>
#include <sstream>
#include <algorithm>
using namespace std;

int solution(vector<int>& nums1, vector<int>& nums2) {
    int n = nums1.size();
    int half = n / 2;

    unordered_set<int> set1(nums1.begin(), nums1.end());
    unordered_set<int> set2(nums2.begin(), nums2.end());

    // Count elements only in nums1
    unordered_set<int> only1;
    for (int num : set1) {
        if (set2.find(num) == set2.end()) {
            only1.insert(num);
        }
    }

    // Count elements only in nums2
    unordered_set<int> only2;
    for (int num : set2) {
        if (set1.find(num) == set1.end()) {
            only2.insert(num);
        }
    }

    // Count common elements
    unordered_set<int> common;
    for (int num : set1) {
        if (set2.find(num) != set2.end()) {
            common.insert(num);
        }
    }

    // From nums1: take unique first, then common if needed
    int takeOnly1 = min((int)only1.size(), half);
    int remainingFrom1 = half - takeOnly1;
    int takeCommonFrom1 = min((int)common.size(), remainingFrom1);

    // From nums2: take unique first, then common if needed
    int takeOnly2 = min((int)only2.size(), half);
    int remainingFrom2 = half - takeOnly2;
    int takeCommonFrom2 = min((int)common.size(), remainingFrom2);

    // Total common elements we can include
    int totalCommonTaken = min((int)common.size(), takeCommonFrom1 + takeCommonFrom2);

    return takeOnly1 + takeOnly2 + totalCommonTaken;
}

