package main

import (
    "bufio"
    "encoding/json"
    "fmt"
    "os"
    "strings"
)

func min(a, b int) int {
    if a < b {
        return a
    }
    return b
}

func solution(nums1, nums2 []int) int {
    n := len(nums1)
    half := n / 2

    set1 := make(map[int]bool)
    set2 := make(map[int]bool)

    for _, num := range nums1 {
        set1[num] = true
    }
    for _, num := range nums2 {
        set2[num] = true
    }

    // Count elements only in nums1
    only1 := make(map[int]bool)
    for num := range set1 {
        if !set2[num] {
            only1[num] = true
        }
    }

    // Count elements only in nums2
    only2 := make(map[int]bool)
    for num := range set2 {
        if !set1[num] {
            only2[num] = true
        }
    }

    // Count common elements
    common := make(map[int]bool)
    for num := range set1 {
        if set2[num] {
            common[num] = true
        }
    }

    // From nums1: take unique first, then common if needed
    takeOnly1 := min(len(only1), half)
    remainingFrom1 := half - takeOnly1
    takeCommonFrom1 := min(len(common), remainingFrom1)

    // From nums2: take unique first, then common if needed
    takeOnly2 := min(len(only2), half)
    remainingFrom2 := half - takeOnly2
    takeCommonFrom2 := min(len(common), remainingFrom2)

    // Total common elements we can include
    totalCommonTaken := min(len(common), takeCommonFrom1 + takeCommonFrom2)

    return takeOnly1 + takeOnly2 + totalCommonTaken
}

func main() {
    reader := bufio.NewReader(os.Stdin)

    line1, _ := reader.ReadString('\n')
    line2, _ := reader.ReadString('\n')

    var nums1, nums2 []int
    json.Unmarshal([]byte(strings.TrimSpace(line1)), &nums1)
    json.Unmarshal([]byte(strings.TrimSpace(line2)), &nums2)

    fmt.Println(solution(nums1, nums2))
}

