int solution(int* nums1, int* nums2, int n) {
    int half = n / 2;

    // Use arrays to track elements (assuming reasonable range)
    int inSet1[2001] = {0};
    int inSet2[2001] = {0};
    int only1Count = 0, only2Count = 0, commonCount = 0;

    // Mark elements in set1
    for (int i = 0; i < n; i++) {
        if (!inSet1[nums1[i] + 1000]) {
            inSet1[nums1[i] + 1000] = 1;
        }
    }

    // Mark elements in set2
    for (int i = 0; i < n; i++) {
        if (!inSet2[nums2[i] + 1000]) {
            inSet2[nums2[i] + 1000] = 1;
        }
    }

    // Count categories
    for (int i = 0; i < 2001; i++) {
        if (inSet1[i] && !inSet2[i]) only1Count++;
        else if (!inSet1[i] && inSet2[i]) only2Count++;
        else if (inSet1[i] && inSet2[i]) commonCount++;
    }

    // From nums1: take unique first, then common if needed
    int takeOnly1 = min(only1Count, half);
    int remainingFrom1 = half - takeOnly1;
    int takeCommonFrom1 = min(commonCount, remainingFrom1);

