#include <iostream>
#include <vector>
#include <unordered_map>
#include <algorithm>
#include <sstream>
#include <string>
using namespace std;

vector<int> solution(vector<int>& nums, vector<int>& freq) {
    unordered_map<int, int> count;
    vector<int> result;

    for (int i = 0; i < nums.size(); i++) {
        // Update frequency
        count[nums[i]] += freq[i];

        // Remove IDs with zero or negative count
        if (count[nums[i]] <= 0) {
            count.erase(nums[i]);
        }

        // Find maximum frequency
        int maxFreq = 0;
        for (auto& pair : count) {
            maxFreq = max(maxFreq, pair.second);
        }

        result.push_back(maxFreq);
    }

    return result;
}

vector<int> parseArray(string s) {
    vector<int> result;
    s = s.substr(1, s.length() - 2); // Remove [ and ]
    if (s.empty()) return result;

    stringstream ss(s);
    string num;
    while (getline(ss, num, ',')) {
        // Remove whitespace
        num.erase(0, num.find_first_not_of(" \t"));
        num.erase(num.find_last_not_of(" \t") + 1);
        if (!num.empty()) {
            result.push_back(stoi(num));
        }
    }
    return result;
}

int main() {
    string line;
    getline(cin, line);
    vector<int> nums = parseArray(line);
    getline(cin, line);
    vector<int> freq = parseArray(line);

    vector<int> result = solution(nums, freq);

    cout << "[";
    for (int i = 0; i < result.size(); i++) {
        cout << result[i];
        if (i < result.size() - 1) cout << ",";
    }
    cout << "]" << endl;

    return 0;
}

