#include <iostream>
#include <vector>
#include <unordered_map>
#include <queue>
#include <sstream>
#include <string>
using namespace std;

vector<int> solution(vector<int>& nums, vector<int>& freq) {
    unordered_map<int, int> count;
    unordered_map<int, int> freqCount;
    priority_queue<int> maxHeap;
    vector<int> result;

    for (int i = 0; i < nums.size(); i++) {
        int oldFreq = count[nums[i]];
        int newFreq = oldFreq + freq[i];

        // Update frequency count
        if (oldFreq > 0) {
            freqCount[oldFreq]--;
            if (freqCount[oldFreq] == 0) {
                freqCount.erase(oldFreq);
            }
        }

        if (newFreq > 0) {
            count[nums[i]] = newFreq;
            freqCount[newFreq]++;
            maxHeap.push(newFreq);
        } else {
            count.erase(nums[i]);
        }

        // Clean heap and find maximum
        while (!maxHeap.empty() && freqCount.find(maxHeap.top()) == freqCount.end()) {
            maxHeap.pop();
        }

        int maxFreq = maxHeap.empty() ? 0 : maxHeap.top();
        result.push_back(maxFreq);
    }

    return result;
}

vector<int> parseArray(string s) {
    vector<int> result;
    s = s.substr(1, s.length() - 2);
    if (s.empty()) return result;

    stringstream ss(s);
    string num;
    while (getline(ss, num, ',')) {
        // Remove whitespace
        num.erase(0, num.find_first_not_of(" \t"));
        num.erase(num.find_last_not_of(" \t") + 1);
        if (!num.empty()) {
            result.push_back(stoi(num));
        }
    }
    return result;
}

