#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Simplified heap implementation
struct MaxHeap {
    int data[10000];
    int size;
};

void heapPush(struct MaxHeap* h, int val) {
    h->data[h->size] = val;
    int idx = h->size;
    h->size++;

    while (idx > 0) {
        int parent = (idx - 1) / 2;
        if (h->data[parent] >= h->data[idx]) break;
        int temp = h->data[parent];
        h->data[parent] = h->data[idx];
        h->data[idx] = temp;
        idx = parent;
    }
}

int heapPop(struct MaxHeap* h) {
    if (h->size == 0) return 0;
    int result = h->data[0];
    h->size--;
    if (h->size > 0) {
        h->data[0] = h->data[h->size];
        int idx = 0;
        while (2 * idx + 1 < h->size) {
            int left = 2 * idx + 1;
            int right = 2 * idx + 2;
            int maxIdx = left;
            if (right < h->size && h->data[right] > h->data[left]) {
                maxIdx = right;
            }
            if (h->data[idx] >= h->data[maxIdx]) break;
            int temp = h->data[idx];
            h->data[idx] = h->data[maxIdx];
            h->data[maxIdx] = temp;
            idx = maxIdx;
        }
    }
    return result;
}

int* solution(int* nums, int numsSize, int* freq, int freqSize, int* returnSize) {
    // Basic frequency counting approach since full heap is complex in C
    struct {
        int id;
        int count;
    } entries[1000];
    int entryCount = 0;
    int* result = (int*)malloc(numsSize * sizeof(int));
    *returnSize = numsSize;

    for (int i = 0; i < numsSize; i++) {
        // Find or create entry for nums[i]
        int found = -1;
        for (int j = 0; j < entryCount; j++) {
            if (entries[j].id == nums[i]) {
                found = j;
                break;
            }
        }

        if (found == -1) {
            entries[entryCount].id = nums[i];
            entries[entryCount].count = freq[i];
            entryCount++;
        } else {
            entries[found].count += freq[i];
        }

        // Remove entries with zero or negative count
        for (int j = 0; j < entryCount; j++) {
            if (entries[j].count <= 0) {
                for (int k = j; k < entryCount - 1; k++) {
                    entries[k] = entries[k + 1];
                }
                entryCount--;
                j--;
            }
        }

        // Find maximum frequency
        int maxFreq = 0;
        for (int j = 0; j < entryCount; j++) {
            if (entries[j].count > maxFreq) {
                maxFreq = entries[j].count;
            }
        }

        result[i] = maxFreq;
    }

    return result;
}

