#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_SIZE 1000

typedef struct {
    int val;
    int freq;
} FreqPair;

int compare(const void* a, const void* b) {
    FreqPair* pa = (FreqPair*)a;
    FreqPair* pb = (FreqPair*)b;
    return pb->freq - pa->freq; // Descending order
}

int solution(int* arr, int arrSize) {
    FreqPair pairs[MAX_SIZE];
    int uniqueCount = 0;

    // Count frequencies
    for (int i = 0; i < arrSize; i++) {
        int found = 0;
        for (int j = 0; j < uniqueCount; j++) {
            if (pairs[j].val == arr[i]) {
                pairs[j].freq++;
                found = 1;
                break;
            }
        }
        if (!found) {
            pairs[uniqueCount].val = arr[i];
            pairs[uniqueCount].freq = 1;
            uniqueCount++;
        }
    }

    // Sort by frequency descending
    qsort(pairs, uniqueCount, sizeof(FreqPair), compare);

    // Greedily pick most frequent
    int target = (arrSize + 1) / 2;
    int removed = 0;
    int count = 0;

    for (int i = 0; i < uniqueCount; i++) {
        removed += pairs[i].freq;
        count++;
        if (removed >= target) {
            return count;
        }
    }

    return count;
}

int main() {
    char line[10000];
    fgets(line, sizeof(line), stdin);

    // Parse array
    int arr[MAX_SIZE];
    int size = 0;
    char* token = strtok(line, "[],\n");
    while (token != NULL && size < MAX_SIZE) {
        if (strlen(token) > 0) {
            arr[size++] = atoi(token);
        }
        token = strtok(NULL, "[],\n");
    }

    printf("%d\n", solution(arr, size));
    return 0;
}

