package main

import (
    "bufio"
    "container/heap"
    "encoding/json"
    "fmt"
    "os"
)

type IntHeap []int

func (h IntHeap) Len() int           { return len(h) }
func (h IntHeap) Less(i, j int) bool { return h[i] > h[j] } // Max heap
func (h IntHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }

func (h *IntHeap) Push(x interface{}) {
    *h = append(*h, x.(int))
}

func (h *IntHeap) Pop() interface{} {
    old := *h
    n := len(old)
    x := old[n-1]
    *h = old[0 : n-1]
    return x
}

func solution(arr []int) int {
    // Count frequencies
    freq := make(map[int]int)
    for _, num := range arr {
        freq[num]++
    }

    // Build max heap
    h := &IntHeap{}
    heap.Init(h)
    for _, f := range freq {
        heap.Push(h, f)
    }

    // Extract most frequent
    target := (len(arr) + 1) / 2
    removed := 0
    count := 0

    for h.Len() > 0 && removed < target {
        removed += heap.Pop(h).(int)
        count++
    }

    return count
}

