#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_SIZE 1000

typedef struct {
    int* data;
    int size;
    int capacity;
} MaxHeap;

MaxHeap* createHeap(int capacity) {
    MaxHeap* heap = malloc(sizeof(MaxHeap));
    heap->data = malloc(capacity * sizeof(int));
    heap->size = 0;
    heap->capacity = capacity;
    return heap;
}

void swap(int* a, int* b) {
    int temp = *a;
    *a = *b;
    *b = temp;
}

void heapifyUp(MaxHeap* heap, int idx) {
    while (idx > 0) {
        int parent = (idx - 1) / 2;
        if (heap->data[parent] >= heap->data[idx]) break;
        swap(&heap->data[parent], &heap->data[idx]);
        idx = parent;
    }
}

void heapifyDown(MaxHeap* heap, int idx) {
    while (1) {
        int largest = idx;
        int left = 2 * idx + 1;
        int right = 2 * idx + 2;

        if (left < heap->size && heap->data[left] > heap->data[largest]) {
            largest = left;
        }
        if (right < heap->size && heap->data[right] > heap->data[largest]) {
            largest = right;
        }

        if (largest == idx) break;
        swap(&heap->data[idx], &heap->data[largest]);
        idx = largest;
    }
}

void push(MaxHeap* heap, int val) {
    heap->data[heap->size] = val;
    heapifyUp(heap, heap->size);
    heap->size++;
}

int pop(MaxHeap* heap) {
    if (heap->size == 0) return -1;
    int max = heap->data[0];
    heap->data[0] = heap->data[--heap->size];
    heapifyDown(heap, 0);
    return max;
}

int solution(int* arr, int arrSize) {
    int freq[MAX_SIZE * 2] = {0}; // Assume values in reasonable range
    int minVal = arr[0], maxVal = arr[0];

    // Find range and count frequencies
    for (int i = 0; i < arrSize; i++) {
        if (arr[i] < minVal) minVal = arr[i];
        if (arr[i] > maxVal) maxVal = arr[i];
    }

    for (int i = 0; i < arrSize; i++) {
        freq[arr[i] - minVal]++;
    }

    // Build max heap with frequencies
    MaxHeap* heap = createHeap(MAX_SIZE);
    for (int i = 0; i <= maxVal - minVal; i++) {
        if (freq[i] > 0) {
            push(heap, freq[i]);
        }
    }

    // Extract most frequent
    int target = (arrSize + 1) / 2;
    int removed = 0;
    int count = 0;

    while (heap->size > 0 && removed < target) {
        removed += pop(heap);
        count++;
    }

    free(heap->data);
    free(heap);
    return count;
}

int main() {
    char line[10000];
    fgets(line, sizeof(line), stdin);

    // Parse array
    int arr[MAX_SIZE];
    int size = 0;
    char* token = strtok(line, "[],\n");
    while (token != NULL && size < MAX_SIZE) {
        if (strlen(token) > 0) {
            arr[size++] = atoi(token);
        }
        token = strtok(NULL, "[],\n");
    }

    printf("%d\n", solution(arr, size));
    return 0;
}

