    for (const num of arr) {
        freq.set(num, (freq.get(num) || 0) + 1);
    }

    const uniqueVals = Array.from(freq.keys());
    const target = Math.ceil(arr.length / 2);

    // Generate all combinations and find minimum
    function combinations(arr, k) {
        if (k === 0) return [[]];
        if (arr.length === 0) return [];
        const [first, ...rest] = arr;
        return combinations(rest, k - 1).map(c => [first, ...c])
            .concat(combinations(rest, k));
    }

    for (let size = 1; size <= uniqueVals.length; size++) {
        const combos = combinations(uniqueVals, size);
        for (const combo of combos) {
            const removed = combo.reduce((sum, val) => sum + freq.get(val), 0);
            if (removed >= target) return size;
        }
    }

    return uniqueVals.length;
