int solution(int* timeSeries, int timeSeriesSize, int duration) {
    if (timeSeriesSize == 0 || duration == 0) {
        return 0;
    }

    int maxTime = timeSeries[timeSeriesSize - 1] + duration;
    bool* poisoned = (bool*)calloc(maxTime + 1, sizeof(bool));

    for (int i = 0; i < timeSeriesSize; i++) {
        int attackTime = timeSeries[i];
        for (int t = attackTime; t < attackTime + duration && t <= maxTime; t++) {
            poisoned[t] = true;
        }
    }

    int count = 0;
    for (int i = 0; i <= maxTime; i++) {
        if (poisoned[i]) count++;
    }

    free(poisoned);
    return count;
}

