    char* start = strchr(line, '[');
    char* end = strchr(line, ']');
    if (start && end && start < end) {
        start++;
        *end = '\0';

        if (start < end) {  // Not empty array
            char* token = strtok(start, ",");
            while (token != NULL) {
                // Skip whitespace
                while (isspace(*token)) token++;
